# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql

def lambda_handler(event, context):
    conn = pymysql.connect(host="your-rds-endpoint",
                            user="username",
                            password="password",
                            db="database")

    cursor = conn.cursor()

    search_params = json.loads(event['body'])

    query_parts = []
    query_parts.append("SELECT * FROM products WHERE 1=1")

    if 'name' in search_params:
        name_search = search_params['name'].lower()
        query_parts.append(f" AND lower(name) LIKE '%{name_search}%'")

    if 'category' in search_params:
        category_id = search_params['category']
        query_parts.append(f" AND id_category={category_id}")

    if 'price' in search_params:
        price_range = search_params['price'].split('-')
        min_price, max_price = map(int, price_range)
        query_parts.append(f" AND price BETWEEN {min_price} AND {max_price}")

    final_query = ' '.join(query_parts)

    cursor.execute(final_query)
    results = cursor.fetchall()

    output = {'products': [{'id': row[0], 'name': row[1], 'category_id': row[2], 'price': row[3]} for row in results]}

    conn.commit()
    cursor.close()
    conn.close()

    return {
        "statusCode": 200,
        "body": json.dumps(output)
    }